package com.app.gerenciadorcartoes.data.local.dao

import androidx.room.Dao
import androidx.room.Insert
import androidx.room.OnConflictStrategy
import androidx.room.Query
import androidx.room.Update
import com.app.gerenciadorcartoes.data.local.entity.CartaoEntity
import kotlinx.coroutines.flow.Flow

@Dao
interface CartaoDao {

    @Query("SELECT * FROM cartoes ORDER BY nomeTitular ASC")
    fun observarTodos(): Flow<List<CartaoEntity>>

    @Query("SELECT * FROM cartoes WHERE id = :id")
    suspend fun buscarPorId(id: Long): CartaoEntity?

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun inserir(entity: CartaoEntity): Long

    @Update
    suspend fun atualizar(entity: CartaoEntity)

    @Query("DELETE FROM cartoes WHERE id = :id")
    suspend fun excluirPorId(id: Long)
}

package com.fsales.app.gerenciadorcartoes.di

import android.content.Context
import androidx.room.Room
import com.fsales.app.gerenciadorcartoes.data.local.dao.ItemDao
import com.fsales.app.gerenciadorcartoes.data.local.database.AppDatabase
import com.fsales.app.gerenciadorcartoes.repository.ItemRepository
import com.fsales.app.gerenciadorcartoes.repository.ItemRepositoryImpl
import dagger.Binds
import dagger.Module
import dagger.Provides
import dagger.hilt.InstallIn
import dagger.hilt.android.qualifiers.ApplicationContext
import dagger.hilt.components.SingletonComponent
import javax.inject.Singleton

@Module
@InstallIn(SingletonComponent::class)
abstract class AppModule {

    @Binds
    @Singleton
    abstract fun bindItemRepository(impl: ItemRepositoryImpl): ItemRepository

    companion object {

        @Provides
        @Singleton
        fun provideDatabase(@ApplicationContext context: Context): AppDatabase =
            Room.databaseBuilder(
                context,
                AppDatabase::class.java,
                "gerenciador-cartoes-db",
            ).build()

        @Provides
        @Singleton
        fun provideItemDao(database: AppDatabase): ItemDao = database.itemDao()
    }
}

