// =============================================================================
// Screen — ponto de entrada da feature; coleta ViewModel e roteia UiEvent.
// Delega toda a renderização para ListaContent.
// =============================================================================
@Composable
fun ListaScreen(
    onNavigateToNovo : () -> Unit,
    onNavigateToItem : (id: Long) -> Unit,
    viewModel        : ListaViewModel = hiltViewModel(),
) {
    val uiState           by viewModel.uiState.collectAsStateWithLifecycle()
    val snackbarHostState  = remember { SnackbarHostState() }

    // Coleta eventos one-shot — LaunchedEffect garante entrega única por recomposição
    LaunchedEffect(viewModel) {
        viewModel.uiEvent.collect { event ->
            when (event) {
                is ListaUiEvent.NavegaParaItem -> onNavigateToItem(event.id)
                ListaUiEvent.NavegaParaNovo    -> onNavigateToNovo()
                is ListaUiEvent.MostrarErro    -> snackbarHostState.showSnackbar(event.mensagem)
            }
        }
    }

    ListaContent(
        uiState           = uiState,
        snackbarHostState = snackbarHostState,
        onEvent           = viewModel::onEvent,
    )
}

// =============================================================================
// Content — renderiza estado puro; sem ViewModel.
// Recebe onEvent como lambda para manter testabilidade e permitir Preview.
// =============================================================================
@Composable
fun ListaContent(
    uiState           : ListaUiState       = ListaUiState(),
    snackbarHostState : SnackbarHostState  = remember { SnackbarHostState() },
    onEvent           : (ListaEvent) -> Unit = {},
) {
    AppScaffold(
        snackbarHostState    = snackbarHostState,
        topBar               = { AppTopAppBar(title = "Lista") },
        floatingActionButton = {
            FloatingActionButton(
                onClick = { onEvent(ListaEvent.NavegaParaNovo) }
            ) {
                Icon(imageVector = Icons.Default.Add, contentDescription = null)
            }
        },
    ) { paddingValues ->
        when {
            uiState.carregando      -> AppLoading()

            uiState.itens.isEmpty() -> EmptyState(
                message  = "Nenhum item encontrado.",
                modifier = Modifier.padding(paddingValues),
            )

            else -> {
                // TODO: Renderizar LazyColumn com uiState.itens
                // Cada item dispara: onEvent(ListaEvent.NavegaParaItem(id))
            }
        }
    }
}

