package com.fsales.app.gerenciadorcartoes.ui.feature.lista

// Eventos one-shot emitidos pelo ViewModel e consumidos uma única vez pela UI.
// Transportados via Channel para evitar reentrega após recomposição.
sealed interface ListaUiEvent {
    /** Navega para tela de detalhe/edição de item existente */
    data class  NavegaParaItem(val id: Long)        : ListaUiEvent
    /** Navega para tela de criação de novo item */
    data object NavegaParaNovo                      : ListaUiEvent
    data class  MostrarErro(val mensagem: String)   : ListaUiEvent
}

package com.app.gerenciadorcartoes.ui.feature.lista

// Eventos one-shot emitidos pelo ViewModel e consumidos uma única vez pela UI.
// Transportados via Channel para evitar reentrega após recomposição.
sealed interface ListaUiEvent {
    /** Navega para tela de detalhe/edição de item existente */
    data class  NavegaParaItem(val id: Long)          : ListaUiEvent
    /** Navega para tela de criação de novo item */
    data object NavegaParaNovo                         : ListaUiEvent
    /** Mostra um erro */
    data class  MostrarErro(val mensagem: String)     : ListaUiEvent
    /** Mostra uma mensagem */
    data class  MostrarMensagem(val mensagem: String) : ListaUiEvent
}

package com.fsales.app.gerenciadorcartoes.ui.feature.lista.state

// Estado imutável da tela de lista.
// Toda a UI é derivada exclusivamente deste data class — sem estado local nas Composables.
data class ListaUiState(
    val itens      : List<String> = emptyList(), // TODO: substituir pelo tipo de domínio correto
    val carregando : Boolean      = false,
    val erro       : String?      = null,
)

package com.fsales.app.gerenciadorcartoes.ui.navigation

import androidx.compose.runtime.Composable
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import androidx.navigation.compose.rememberNavController
import com.fsales.app.gerenciadorcartoes.ui.feature.detalhe.DetalheScreen
import com.fsales.app.gerenciadorcartoes.ui.feature.lista.ListaScreen

// NavHost principal do aplicativo.
// Usa Navigation Compose 2 type-safe: composable<T>{} com rotas @Serializable.
// Para adicionar novas telas: declare a rota em Routes.kt e registre um composable<T>{} abaixo.
@Composable
fun AppNavHost() {
    val navController = rememberNavController()

    NavHost(
        navController  = navController,
        startDestination = ListaRoute,
    ) {

        composable<ListaRoute> {
            ListaScreen(
                onNavigateToNovo = {
                    navController.navigate(DetalheRoute(id = 0L))
                },
                onNavigateToItem = { id ->
                    navController.navigate(DetalheRoute(id = id))
                },
            )
        }

        composable<DetalheRoute> {
            DetalheScreen(
                navigateBack = { navController.popBackStack() },
            )
        }
    }
}

package com.app.gerenciadorcartoes.ui.navigation

import androidx.compose.runtime.Composable
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import androidx.navigation.compose.rememberNavController
import com.app.gerenciadorcartoes.ui.feature.cadastraralterar.CadastrarAlterarScreen
import com.app.gerenciadorcartoes.ui.feature.detalhe.DetalheScreen
import com.app.gerenciadorcartoes.ui.feature.lista.ListaScreen

@Composable
fun AppNavHost() {
    val navController = rememberNavController()

    NavHost(
        navController    = navController,
        startDestination = ListaRoute,
    ) {

        composable<ListaRoute> {
            ListaScreen(
                onNavigateToNovo = {
                    navController.navigate(CadastrarAlterarRoute(id = 0L))
                },
                onNavigateToItem = { id ->
                    navController.navigate(DetalheRoute(id = id))
                },
            )
        }

        composable<DetalheRoute> {
            DetalheScreen(
                navigateBack       = { navController.popBackStack() },
                onNavigateToEditar = { id ->
                    navController.navigate(CadastrarAlterarRoute(id = id))
                },
            )
        }

        composable<CadastrarAlterarRoute> {
            CadastrarAlterarScreen(
                navigateBack = { navController.popBackStack() },
            )
        }
    }
}

package com.fsales.app.gerenciadorcartoes.ui.navigation

import kotlinx.serialization.Serializable

// Rota da tela de lista — destino inicial
@Serializable
object ListaRoute

// Rota da tela de detalhe — recebe o id do item
// Navigation Compose 2 cria um ViewModelStoreOwner único por entrada no back stack.
@Serializable
data class DetalheRoute(val id: Long)

package com.app.gerenciadorcartoes.ui.navigation

import kotlinx.serialization.Serializable

// Destino: lista de cartões (tela inicial)
@Serializable
object ListaRoute

// Destino: detalhes de um cartão específico
@Serializable
data class DetalheRoute(val id: Long)

// Destino: formulário de cadastro (id=0) ou edição (id>0)
@Serializable
data class CadastrarAlterarRoute(val id: Long = 0L)

package com.fsales.app.gerenciadorcartoes.ui.theme

import androidx.compose.material3.MaterialTheme
import androidx.compose.runtime.Composable
import androidx.compose.runtime.ReadOnlyComposable
import androidx.compose.runtime.compositionLocalOf
import androidx.compose.ui.unit.Dp
import androidx.compose.ui.unit.dp

// =============================================================================
// Tokens de tamanho de ícone — escala oficial MD3
// https://m3.material.io/styles/icons/specs
// =============================================================================
data class IconSize(
    /** 16dp — ícones em componentes compactos (chips, badges) */
    val extraSmall : Dp = 16.dp,
    /** 20dp — ícones em componentes densos (listas compactas) */
    val small      : Dp = 20.dp,
    /** 24dp — ícones padrão (NavigationBar, botões, campos) */
    val medium     : Dp = 24.dp,
    /** 40dp — ícones grandes (FAB, itens de lista com destaque) */
    val large      : Dp = 40.dp,
    /** 48dp — ícones de destaque (cards hero, onboarding) */
    val extraLarge : Dp = 48.dp,
)

val LocalIconSize = compositionLocalOf { IconSize() }

/** Acesso ao sistema de tamanho de ícone via MaterialTheme — uso: MaterialTheme.iconSize.medium */
val MaterialTheme.iconSize: IconSize
    @Composable
    @ReadOnlyComposable
    get() = LocalIconSize.current

