package com.fsales.app.gerenciadorcartoes.viewmodel

import androidx.lifecycle.SavedStateHandle
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import androidx.navigation.toRoute
import com.fsales.app.gerenciadorcartoes.repository.ItemRepository
import com.fsales.app.gerenciadorcartoes.ui.feature.detalhe.DetalheEvent
import com.fsales.app.gerenciadorcartoes.ui.feature.detalhe.DetalheUiEvent
import com.fsales.app.gerenciadorcartoes.ui.feature.detalhe.state.DetalheUiState
import com.fsales.app.gerenciadorcartoes.ui.navigation.DetalheRoute
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.channels.Channel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.receiveAsFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch
import javax.inject.Inject

@HiltViewModel
class DetalheViewModel @Inject constructor(
    savedStateHandle      : SavedStateHandle,
    private val itemRepository: ItemRepository,
) : ViewModel() {

    // Recupera a rota tipada via SavedStateHandle — Navigation Compose 2.8+
    private val route : DetalheRoute = savedStateHandle.toRoute()
    private val id    : Long         = route.id

    private val _uiState = MutableStateFlow(DetalheUiState(id = id, carregando = true))
    val uiState: StateFlow<DetalheUiState> = _uiState.asStateFlow()

    private val _uiEvent = Channel<DetalheUiEvent>(Channel.BUFFERED)
    val uiEvent = _uiEvent.receiveAsFlow()

    init {
        carregarItem()
    }

    fun onEvent(event: DetalheEvent) {
        when (event) {
            DetalheEvent.Voltar -> viewModelScope.launch {
                _uiEvent.send(DetalheUiEvent.NavigateBack)
            }
        }
    }

    private fun carregarItem() {
        viewModelScope.launch {
            runCatching {
                // TODO: val item = itemRepository.getItemById(id)
                // _uiState.update { it.copy(titulo = item.titulo, carregando = false) }
                _uiState.update { it.copy(carregando = false) }
            }.onFailure { erro ->
                _uiState.update { it.copy(carregando = false, erro = erro.message) }
                _uiEvent.send(DetalheUiEvent.MostrarErro(erro.message ?: "Erro desconhecido"))
            }
        }
    }
}

package com.app.gerenciadorcartoes.viewmodel

import androidx.lifecycle.SavedStateHandle
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import androidx.navigation.toRoute
import com.app.gerenciadorcartoes.repository.CartaoRepository
import com.app.gerenciadorcartoes.ui.feature.detalhe.DetalheEvent
import com.app.gerenciadorcartoes.ui.feature.detalhe.DetalheUiEvent
import com.app.gerenciadorcartoes.ui.feature.detalhe.state.DetalheUiState
import com.app.gerenciadorcartoes.ui.navigation.DetalheRoute
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.channels.Channel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.receiveAsFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch
import javax.inject.Inject

@HiltViewModel
class DetalheViewModel @Inject constructor(
    savedStateHandle        : SavedStateHandle,
    private val cartaoRepository: CartaoRepository,
) : ViewModel() {

    private val route : DetalheRoute = savedStateHandle.toRoute()
    private val id    : Long          = route.id

    private val _uiState = MutableStateFlow(DetalheUiState(carregando = true))
    val uiState: StateFlow<DetalheUiState> = _uiState.asStateFlow()

    private val _uiEvent = Channel<DetalheUiEvent>(Channel.BUFFERED)
    val uiEvent = _uiEvent.receiveAsFlow()

    init {
        carregarCartao()
    }

    fun onEvent(event: DetalheEvent) {
        when (event) {
            DetalheEvent.Voltar  -> viewModelScope.launch { _uiEvent.send(DetalheUiEvent.NavigateBack) }
            DetalheEvent.Editar  -> viewModelScope.launch { _uiEvent.send(DetalheUiEvent.NavegaParaEditar(id)) }
            DetalheEvent.Excluir -> excluir()
        }
    }

    private fun carregarCartao() {
        viewModelScope.launch {
            runCatching {
                val cartao = cartaoRepository.buscarPorId(id)
                if (cartao != null) {
                    _uiState.update { it.copy(cartao = cartao, carregando = false) }
                } else {
                    _uiState.update { it.copy(carregando = false) }
                    _uiEvent.send(DetalheUiEvent.NavigateBack)
                }
            }.onFailure { erro ->
                _uiState.update { it.copy(carregando = false, erro = erro.message) }
                _uiEvent.send(DetalheUiEvent.MostrarErro(erro.message ?: "Erro ao carregar cartão"))
            }
        }
    }

    private fun excluir() {
        viewModelScope.launch {
            runCatching {
                cartaoRepository.excluirPorId(id)
                _uiEvent.send(DetalheUiEvent.NavigateBack)
            }.onFailure { erro ->
                _uiEvent.send(DetalheUiEvent.MostrarErro(erro.message ?: "Erro ao excluir cartão"))
            }
        }
    }
}

package com.fsales.app.gerenciadorcartoes.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.fsales.app.gerenciadorcartoes.repository.ItemRepository
import com.fsales.app.gerenciadorcartoes.ui.feature.lista.ListaEvent
import com.fsales.app.gerenciadorcartoes.ui.feature.lista.ListaUiEvent
import com.fsales.app.gerenciadorcartoes.ui.feature.lista.state.ListaUiState
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.channels.Channel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.receiveAsFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch
import javax.inject.Inject

@HiltViewModel
class ListaViewModel @Inject constructor(
    private val itemRepository: ItemRepository,
) : ViewModel() {

    // Estado da tela — StateFlow para observação contínua
    private val _uiState = MutableStateFlow(ListaUiState(carregando = true))
    val uiState: StateFlow<ListaUiState> = _uiState.asStateFlow()

    // Eventos one-shot (navegação, snackbar) — Channel para entrega única
    private val _uiEvent = Channel<ListaUiEvent>(Channel.BUFFERED)
    val uiEvent = _uiEvent.receiveAsFlow()

    init {
        carregarItens()
    }

    fun onEvent(event: ListaEvent) {
        when (event) {
            is ListaEvent.NavegaParaItem -> viewModelScope.launch {
                _uiEvent.send(ListaUiEvent.NavegaParaItem(id = event.id))
            }
            ListaEvent.NavegaParaNovo -> viewModelScope.launch {
                _uiEvent.send(ListaUiEvent.NavegaParaNovo)
            }
        }
    }

    private fun carregarItens() {
        viewModelScope.launch {
            runCatching {
                // TODO: itemRepository.observeItens().collect { itens ->
                //     _uiState.update { it.copy(itens = itens, carregando = false) }
                // }
                _uiState.update { it.copy(carregando = false) }
            }.onFailure { erro ->
                _uiState.update { it.copy(carregando = false, erro = erro.message) }
                _uiEvent.send(ListaUiEvent.MostrarErro(erro.message ?: "Erro desconhecido"))
            }
        }
    }
}

package com.app.gerenciadorcartoes.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.app.gerenciadorcartoes.repository.CartaoRepository
import com.app.gerenciadorcartoes.ui.feature.lista.ListaEvent
import com.app.gerenciadorcartoes.ui.feature.lista.ListaUiEvent
import com.app.gerenciadorcartoes.ui.feature.lista.state.ListaUiState
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.channels.Channel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.receiveAsFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch
import javax.inject.Inject

@HiltViewModel
class ListaViewModel @Inject constructor(
    private val cartaoRepository: CartaoRepository,
) : ViewModel() {

    private val _uiState = MutableStateFlow(ListaUiState(carregando = true))
    val uiState: StateFlow<ListaUiState> = _uiState.asStateFlow()

    private val _uiEvent = Channel<ListaUiEvent>(Channel.BUFFERED)
    val uiEvent = _uiEvent.receiveAsFlow()

    init {
        observarCartoes()
    }

    fun onEvent(event: ListaEvent) {
        when (event) {
            is ListaEvent.NavegaParaItem ->
                viewModelScope.launch { _uiEvent.send(ListaUiEvent.NavegaParaItem(event.id)) }

            ListaEvent.NavegaParaNovo ->
                viewModelScope.launch { _uiEvent.send(ListaUiEvent.NavegaParaNovo) }

            is ListaEvent.ExcluirCartao -> excluir(event.id)
        }
    }

    private fun observarCartoes() {
        viewModelScope.launch {
            runCatching {
                cartaoRepository.observarTodos().collect { cartoes ->
                    _uiState.update { it.copy(cartoes = cartoes, carregando = false) }
                }
            }.onFailure { erro ->
                _uiState.update { it.copy(carregando = false, erro = erro.message) }
                _uiEvent.send(ListaUiEvent.MostrarErro(erro.message ?: "Erro ao carregar cartões"))
            }
        }
    }

    private fun excluir(id: Long) {
        viewModelScope.launch {
            runCatching {
                cartaoRepository.excluirPorId(id)
                _uiEvent.send(ListaUiEvent.MostrarMensagem("Cartão removido com sucesso"))
            }.onFailure { erro ->
                _uiEvent.send(ListaUiEvent.MostrarErro(erro.message ?: "Erro ao remover cartão"))
            }
        }
    }
}
